// Paste in browser DevTools Console to test WebSocket connectivity
const ws = new WebSocket('wss://api.anthropic.com/v1/ws-health');
ws.onopen = () => { console.log('WebSocket OK'); ws.close(); };
ws.onerror = (e) => console.error('WebSocket blocked or failed:', e);
// Expected: WebSocket OK
// If error: IT firewall may be blocking WebSocket upgrades on port 443
